const item = $json.output?.[0] || $json;

// defina o ano de referência
const referenceYear = 2026;

function normalizeBrazilianDateTime(value, year = referenceYear) {
  if (!value || typeof value !== 'string') return '';

  const text = value.trim().toLowerCase();

  // já está em iso local
  if (/^\d{4}-\d{2}-\d{2}t\d{2}:\d{2}:\d{2}$/.test(text)) {
    return text.toUpperCase();
  }

  // formatos aceitos:
  // 16/03 às 14h
  // 17/03 às 10h30
  // 16/03 14:00
  // 17/03 10h30
  const match = text.match(/(\d{1,2})\/(\d{1,2})(?:\s*(?:às)?\s*)(\d{1,2})(?:[:h](\d{2}))?/i);

  if (!match) return '';

  const [, dd, mm, hh, min] = match;

  const day = String(dd).padStart(2, '0');
  const month = String(mm).padStart(2, '0');
  const hour = String(hh).padStart(2, '0');
  const minute = String(min || '00').padStart(2, '0');

  return `${year}-${month}-${day}T${hour}:${minute}:00`;
}

return [
  {
    json: {
      ...item,
      selected_option_start: normalizeBrazilianDateTime(item.selected_option_start),
      option_1_start: normalizeBrazilianDateTime(item.option_1_start),
      option_2_start: normalizeBrazilianDateTime(item.option_2_start),
    }
  }
];

// Histórico longo para CRM
// Usa apenas Merge2
// Pega últimas mensagens úteis
// Corrige speaker de transcrição interna de áudio
// Evita duplicar áudio nulo + transcrição
// Saída única

const LIMIT = $input.first().json.qtd_historico || 30;
const OUTGOING_NAME = 'Julia Gabriela';

// Pega todos os itens do Merge2
const inputItems = $input.all();

function normalizeContent(text) {
  return String(text || '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function isInternalAudioTranscript(msg) {
  const content = String(msg.content || '');
  return content.startsWith('[TRANSCRIÇÃO INTERNA DO ÁUDIO');
}

function extractReferencedMessageId(msg) {
  const inReplyTo = msg?.content_attributes?.in_reply_to;
  if (inReplyTo) return Number(inReplyTo);

  const content = String(msg.content || '');
  const match = content.match(/msg_id\s+(\d+)/i);
  return match ? Number(match[1]) : null;
}

function getSpeakerFromType(messageType) {
  const type = Number(messageType);
  if (type === 0) return 'Lead';
  if (type === 1) return OUTGOING_NAME;
  return 'Sistema';
}

function getSpeaker(msg, messageMap) {
  if (isInternalAudioTranscript(msg)) {
    const referencedId = extractReferencedMessageId(msg);
    const originalMsg = referencedId ? messageMap.get(referencedId) : null;

    if (originalMsg) {
      return getSpeakerFromType(originalMsg.message_type);
    }
  }

  return getSpeakerFromType(msg.message_type);
}

function cleanTranscriptContent(text) {
  const content = String(text || '');

  if (!content.startsWith('[TRANSCRIÇÃO INTERNA DO ÁUDIO')) {
    return normalizeContent(content);
  }

  return normalizeContent(
    content
      .replace(/^\[TRANSCRIÇÃO INTERNA DO ÁUDIO[^\n]*\]\n?/i, '')
      .replace(/^⬇️Transcrição do áudio⬇️[^\n]*\n?/i, '')
  );
}

// 1. Extrair mensagens
const rawMessages = inputItems
  .map(item => item.json)
  .filter(j => j && typeof j === 'object' && j.id);

// 2. Remover duplicados por id
const uniqueMap = new Map();
for (const msg of rawMessages) {
  uniqueMap.set(Number(msg.id), msg);
}

let messages = Array.from(uniqueMap.values());

// 3. Ordenar por id crescente primeiro
messages.sort((a, b) => Number(a.id) - Number(b.id));

// 4. Criar mapa completo por id
const messageMap = new Map();
for (const msg of messages) {
  messageMap.set(Number(msg.id), msg);
}

// 5. Descobrir quais mensagens de áudio possuem transcrição interna
const transcribedOriginalIds = new Set();

for (const msg of messages) {
  if (isInternalAudioTranscript(msg)) {
    const referencedId = extractReferencedMessageId(msg);
    if (referencedId) {
      transcribedOriginalIds.add(referencedId);
    }
  }
}

// 6. Filtrar mensagens úteis
messages = messages.filter(msg => {
  const type = Number(msg.message_type);

  // Só mantém type 0 e 1
  if (!(type === 0 || type === 1)) return false;

  // Remove mensagens privadas, exceto transcrição interna
  if (msg.private === true && !isInternalAudioTranscript(msg)) return false;

  // Remove o áudio original sem conteúdo quando já existe transcrição
  const hasEmptyContent = !normalizeContent(msg.content);
  if (hasEmptyContent && transcribedOriginalIds.has(Number(msg.id))) return false;

  // Remove mensagens vazias comuns
  if (hasEmptyContent && !isInternalAudioTranscript(msg)) return false;

  return true;
});

// 7. Pegar só as últimas N
const lastMessages = messages.slice(-LIMIT);

// 8. Montar texto pro CRM
const historyText = lastMessages
  .map(msg => {
    const speaker = getSpeaker(msg, messageMap);
    const content = cleanTranscriptContent(msg.content);

    return `${speaker}: ${content}`;
  })
  .join('\n');

// 9. Saída única
return [
  {
    json: {
      messages_total_received: rawMessages.length,
      messages_total_unique: uniqueMap.size,
      messages_total_filtered: messages.length,
      messages_sent_to_crm: lastMessages.length,
      first_message_id: lastMessages.length ? lastMessages[0].id : null,
      last_message_id: lastMessages.length ? lastMessages[lastMessages.length - 1].id : null,
      history_for_crm: historyText,
      messages_for_crm: lastMessages
    }
  }
];

